class PoolRequest:
    def __init__(self, request: Request) -> None:
        """Create a PoolRequest to track a request and its assigned connection.

        The PoolRequest holds the Request being made and, once a connection is
        available, a reference to the ConnectionInterface that will perform the
        request. It also provides an Event used to wait for a connection to be
        assigned.
        """
        self.request = request
        self.connection: ConnectionInterface | None = None
        self._connection_acquired = Event()

    def assign_to_connection(self, connection: ConnectionInterface | None) -> None:
        """Assign a connection to this PoolRequest and notify any waiters.

        Parameters:
            connection: The connection assigned to handle the request, or None
                to indicate no connection is available.
        """
        self.connection = connection
        self._connection_acquired.set()

    def clear_connection(self) -> None:
        """Clear the assigned connection and reset the internal wait event.

        This is used when the PoolRequest should be put back into a queued
        state before being assigned a connection again.
        """
        self.connection = None
        self._connection_acquired = Event()

    def wait_for_connection(
        self, timeout: float | None = None
    ) -> ConnectionInterface:
        """Wait until a connection is assigned to this PoolRequest.

        If a connection is already assigned, it is returned immediately.
        Otherwise this will block until a connection is assigned or until the
        optional timeout elapses.

        Parameters:
            timeout: Maximum number of seconds to wait for a connection, or None
                to wait indefinitely.

        Returns:
            The assigned ConnectionInterface.
        """
        if self.connection is None:
            self._connection_acquired.wait(timeout=timeout)
        assert self.connection is not None
        return self.connection

    def is_queued(self) -> bool:
        """Return True if this PoolRequest does not yet have an assigned connection."""
        return self.connection is None


class ConnectionPool(RequestInterface):
    """
    A connection pool for making HTTP requests.
    """

    def __init__(
        self,
        ssl_context: ssl.SSLContext | None = None,
        proxy: Proxy | None = None,
        max_connections: int | None = 10,
        max_keepalive_connections: int | None = None,
        keepalive_expiry: float | None = None,
        http1: bool = True,
        http2: bool = False,
        retries: int = 0,
        local_address: str | None = None,
        uds: str | None = None,
        network_backend: NetworkBackend | None = None,
        socket_options: typing.Iterable[SOCKET_OPTION] | None = None,
    ) -> None:
        """
        A connection pool for making HTTP requests.

        Parameters:
            ssl_context: An SSL context to use for verifying connections.
                If not specified, the default `httpcore.default_ssl_context()`
                will be used.
            max_connections: The maximum number of concurrent HTTP connections that
                the pool should allow. Any attempt to send a request on a pool that
                would exceed this amount will block until a connection is available.
            max_keepalive_connections: The maximum number of idle HTTP connections
                that will be maintained in the pool.
            keepalive_expiry: The duration in seconds that an idle HTTP connection
                may be maintained for before being expired from the pool.
            http1: A boolean indicating if HTTP/1.1 requests should be supported
                by the connection pool. Defaults to True.
            http2: A boolean indicating if HTTP/2 requests should be supported by
                the connection pool. Defaults to False.
            retries: The maximum number of retries when trying to establish a
                connection.
            local_address: Local address to connect from. Can also be used to connect
                using a particular address family. Using `local_address="0.0.0.0"`
                will connect using an `AF_INET` address (IPv4), while using
                `local_address="::"` will connect using an `AF_INET6` address (IPv6).
            uds: Path to a Unix Domain Socket to use instead of TCP sockets.
            network_backend: A backend instance to use for handling network I/O.
            socket_options: Socket options that have to be included
             in the TCP socket when the connection was established.
        """
        self._ssl_context = ssl_context
        self._proxy = proxy
        self._max_connections = (
            sys.maxsize if max_connections is None else max_connections
        )